exercises.prompt:
Tienes dos funciones async que simulan operaciones:

```js
async function paso1() { return 'primer resultado'; }
async function paso2(input) { return `${input} procesado`; }
```

Usando `await`, obtén el resultado de `paso1`, pásalo a `paso2`, y asigna el resultado final a `resultadoFinal`.

exercises.starterCode:
async function paso1() { return 'primer resultado'; }
async function paso2(input) { return `${input} procesado`; }

const r1 = await paso1();
const resultadoFinal = await paso2(r1);

async function dividirSeguro(a, b) {
  if (b === 0) throw new Error('División por cero');
  return a / b;
}

let mensajeError;

async function calcular() {
  try {
    await dividirSeguro(10, 0);
  } catch (error) {
    mensajeError = error.message;
  }
}

await calcular();
